import{_ as o,o as s,c as r,ai as t}from"./chunks/framework.CaiDwmc7.js";const h=JSON.parse('{"title":"消息重复消费与幂等性设计","description":"","frontmatter":{},"headers":[],"relativePath":"mq/message-duplicate.md","filePath":"mq/message-duplicate.md"}'),i={name:"mq/message-duplicate.md"};function l(a,e,n,d,c,g){return s(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="消息重复消费与幂等性设计" tabindex="-1">消息重复消费与幂等性设计 <a class="header-anchor" href="#消息重复消费与幂等性设计" aria-label="Permalink to “消息重复消费与幂等性设计”">​</a></h1><hr><h3 id="❓-面试官-如果因为网络原因-mq-把一条消息给消费者投递了两次-怎么保证不会重复扣款-发货-什么是幂等性" tabindex="-1">❓ 面试官：如果因为网络原因，MQ 把一条消息给消费者投递了两次，怎么保证不会重复扣款/发货？（什么是幂等性？） <a class="header-anchor" href="#❓-面试官-如果因为网络原因-mq-把一条消息给消费者投递了两次-怎么保证不会重复扣款-发货-什么是幂等性" aria-label="Permalink to “❓ 面试官：如果因为网络原因，MQ 把一条消息给消费者投递了两次，怎么保证不会重复扣款/发货？（什么是幂等性？）”">​</a></h3><p><em>频率：🔥🔥🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong><strong>MQ 自身是无法完全避免消息重复投递的</strong>。我们必须在<strong>消费者（业务代码）层面</strong>做好防重设计，也就是实现<strong>“幂等性”</strong>（无论这条消息被消费 1 次还是 100 次，最终对数据库的影响都和消费 1 次一模一样）。 最通用的解决方案是：<strong>业务唯一键 + 数据库唯一索引 / Redis 防重表</strong>。</p><p><strong>📝 详细原理解析与常见坑点：</strong></p><ol><li><p><strong>为什么 MQ 会重复投递？</strong></p><ul><li>消费者其实已经把数据库更完了，但在向 MQ 发送 <code>ACK 确认</code> 时，网络突然闪断。MQ 没收到确认，以为消费者挂了或者消费失败了。</li><li>过了几分钟，MQ 为了保证“至少被消费一次”，就会把这条消息重新发给另一个（或者同一个）消费者，这就是典型的重复投递。</li></ul></li><li><p><strong>如果没做幂等的灾难</strong>：</p><ul><li>收到消息：<code>update account set balance = balance - 100 where uid = 1</code>。</li><li>这是一条<strong>相对更新</strong>的 SQL，不具备天然幂等性。如果被消费了两次，用户的余额会被扣掉 200！</li></ul></li></ol><hr><h3 id="❓-面试官-那你们在代码里具体是怎么实现幂等性的-【中高级】" tabindex="-1">❓ 面试官：那你们在代码里具体是怎么实现幂等性的？【中高级】 <a class="header-anchor" href="#❓-面试官-那你们在代码里具体是怎么实现幂等性的-【中高级】" aria-label="Permalink to “❓ 面试官：那你们在代码里具体是怎么实现幂等性的？【中高级】”">​</a></h3><p><em>频率：🔥🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong> 我们会强制要求生产者在发消息时，必须带上一个<strong>全局唯一的业务 ID</strong>（如订单号、交易流水号）。消费端拿到消息后，先用这个 ID 去数据库或者 Redis 里查一下状态，如果发现已经处理过，直接返回成功。</p><p><strong>📝 三大主流防重落地实战方案对比：</strong></p><h4 id="方案一-强依赖数据库唯一索引-最推荐、最稳妥" tabindex="-1">方案一：强依赖数据库唯一索引（最推荐、最稳妥） <a class="header-anchor" href="#方案一-强依赖数据库唯一索引-最推荐、最稳妥" aria-label="Permalink to “方案一：强依赖数据库唯一索引（最推荐、最稳妥）”">​</a></h4><ul><li><strong>核心思想</strong>：依靠 MySQL 自身的防重机制，绝不相信代码里的判断。</li><li><strong>实战做法</strong>： <ol><li>建一张独立的“消费流水防重表”（包含 <code>msg_id</code>，并把它设为<strong>唯一索引 UNIQUE KEY</strong>）。</li><li>收到消息时，开启本地事务。</li><li>执行核心业务 SQL（比如扣余额）。</li><li>往防重表里 <code>INSERT INTO 防重表 (msg_id) VALUES (流水号)</code>。</li><li><strong>提交事务</strong>。</li></ol></li><li><strong>妙处所在</strong>：如果消息重复来了第二次。它试图在同一个事务里往防重表里插入同样的 <code>msg_id</code>。此时 MySQL 的唯一索引会直接抛出 <code>DuplicateKeyException</code> 异常导致整个事务回滚！巧妙地利用了数据库特性阻断了重复消费。</li></ul><h4 id="方案二-乐观锁-适合带状态流转的业务" tabindex="-1">方案二：乐观锁（适合带状态流转的业务） <a class="header-anchor" href="#方案二-乐观锁-适合带状态流转的业务" aria-label="Permalink to “方案二：乐观锁（适合带状态流转的业务）”">​</a></h4><ul><li><strong>核心思想</strong>：利用数据自身的版本号或状态机。</li><li><strong>实战做法</strong>： <ol><li>给订单表加上一个 <code>version</code> 字段，或者利用天然的 <code>status</code> 字段（如 0-待支付，1-已支付）。</li><li>消费者执行更新时，带上预期状态条件： <code>UPDATE order SET status = 1 WHERE order_id = 123 AND status = 0;</code></li><li>如果重复消息来了，它去执行这句 SQL 时，发现数据库里的 <code>status</code> 已经是 1 了，这句 SQL 的受影响行数就是 0，等于什么都没做（天然幂等）。</li></ol></li></ul><h4 id="方案三-redis-分布式锁防重-适合超高并发场景" tabindex="-1">方案三：Redis 分布式锁防重（适合超高并发场景） <a class="header-anchor" href="#方案三-redis-分布式锁防重-适合超高并发场景" aria-label="Permalink to “方案三：Redis 分布式锁防重（适合超高并发场景）”">​</a></h4><ul><li><strong>痛点</strong>：如果并发极高，每次都去 MySQL 查一下或者依赖唯一索引报错，数据库压力太大。</li><li><strong>实战做法</strong>： <ol><li>消费者收到消息，先去 Redis 里执行 <code>SETNX order_123_processed 1 EX 3600</code>。</li><li>如果 <code>SETNX</code> 成功（返回 1），说明是第一次来，继续往下执行去改数据库。</li><li>如果 <code>SETNX</code> 失败（返回 0），说明这个订单已经有线程在处理了，或者已经处理过了，直接丢弃这条重复消息。</li></ol></li><li><strong>隐患（大坑）</strong>：如果 Redis <code>SETNX</code> 成功了，但随后去改 MySQL 时报错了（比如余额不足抛了异常回滚）。此时 Redis 里已经有记录了！当下一次重试的合法消息再过来时，会被 Redis 误认为是重复消息直接拦截掉，导致这笔订单永远卡死。 <ul><li><strong>终极修补</strong>：必须在 catch 块里把 Redis 里的 Key 删掉，或者采用方案一的强事务一致性。</li></ul></li></ul><p><strong>🌟 面试拔高总结：</strong> &quot;日常简单的幂等我们用<strong>状态机/乐观锁</strong>；如果是对账、资金类的绝对核心链路，必定采用<strong>同库的防重表强事务</strong>；如果是大促秒杀的流量洪峰，为了性能我们会前置一层 <strong>Redis SETNX 拦截</strong>作为第一道防线。组合使用才是大厂真实的架构。&quot;</p>',19)])])}const m=o(i,[["render",l]]);export{h as __pageData,m as default};
